import request from '@/utils/request'

export function getCommonMajor(searchParams, isNotify) {
  return request({
    url: `/api/getCommonMajor`,
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data : searchParams,
    Notify: { use: isNotify, apitype: 'searched' }
  })
}

